import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import IssueCard from '../components/IssueCard';

const Dashboard = () => {
  const { user } = useAuth();
  const [issues, setIssues] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState({ type: '', status: '' });
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchIssues();
  }, [filter, searchTerm]);

  const fetchIssues = async () => {
    try {
      const params = new URLSearchParams();
      if (filter.type) params.append('type', filter.type);
      if (filter.status) params.append('status', filter.status);

      const response = await axios.get(`http://localhost:5000/api/issues?${params}`);
      let filteredIssues = response.data.issues;

      // Apply search filter
      if (searchTerm) {
        filteredIssues = filteredIssues.filter(issue =>
          issue.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
          issue.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
          issue.location?.address?.toLowerCase().includes(searchTerm.toLowerCase())
        );
      }

      setIssues(filteredIssues);
    } catch (error) {
      console.error('Error fetching issues:', error);
    } finally {
      setLoading(false);
    }
  };

  const updateIssueStatus = async (issueId, newStatus) => {
    try {
      await axios.put(`http://localhost:5000/api/issues/${issueId}/status`, {
        status: newStatus
      });

      // Update local state
      setIssues(issues.map(issue => 
        issue._id === issueId 
          ? { ...issue, status: newStatus, updatedAt: new Date() }
          : issue
      ));
    } catch (error) {
      console.error('Error updating issue status:', error);
      alert('Error updating issue status');
    }
  };

  const getStats = () => {
    const total = issues.length;
    const pending = issues.filter(i => i.status === 'pending').length;
    const inProgress = issues.filter(i => i.status === 'in_progress').length;
    const resolved = issues.filter(i => i.status === 'resolved').length;

    return { total, pending, inProgress, resolved };
  };

  const stats = getStats();

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64 bg-surface">
        <div className="text-center">
          <span className="material-symbols-outlined animate-spin text-4xl text-primary mb-4">refresh</span>
          <div className="text-lg text-on-surface-variant">Loading infrastructure issues...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-surface font-body text-on-surface">
      {/* Header */}
      <div className="bg-surface-container-lowest border-b border-outline-variant/30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="font-headline font-extrabold text-3xl text-on-surface">CivicWatch Dashboard</h1>
              <p className="text-on-surface-variant mt-2">Monitor and manage city infrastructure issues</p>
            </div>
            <div className="text-right">
              <div className="text-2xl font-bold text-primary">{stats.total}</div>
              <div className="text-on-surface-variant text-sm">Total Issues</div>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
          <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-outline-variant/30 p-6">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-primary-container rounded-lg p-3">
                <span className="material-symbols-outlined text-2xl text-primary">dashboard</span>
              </div>
              <div className="ml-4">
                <div className="text-2xl font-bold text-on-surface">{stats.total}</div>
                <div className="text-sm text-on-surface-variant">Total Issues</div>
              </div>
            </div>
          </div>

          <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-outline-variant/30 p-6">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-tertiary-container rounded-lg p-3">
                <span className="material-symbols-outlined text-2xl text-tertiary">pending</span>
              </div>
              <div className="ml-4">
                <div className="text-2xl font-bold text-tertiary">{stats.pending}</div>
                <div className="text-sm text-on-surface-variant">Pending</div>
              </div>
            </div>
          </div>

          <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-outline-variant/30 p-6">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-primary-container rounded-lg p-3">
                <span className="material-symbols-outlined text-2xl text-primary">engineering</span>
              </div>
              <div className="ml-4">
                <div className="text-2xl font-bold text-primary">{stats.inProgress}</div>
                <div className="text-sm text-on-surface-variant">In Progress</div>
              </div>
            </div>
          </div>

          <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-outline-variant/30 p-6">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-secondary-container rounded-lg p-3">
                <span className="material-symbols-outlined text-2xl text-secondary">check_circle</span>
              </div>
              <div className="ml-4">
                <div className="text-2xl font-bold text-secondary">{stats.resolved}</div>
                <div className="text-sm text-on-surface-variant">Resolved</div>
              </div>
            </div>
          </div>
        </div>

        {/* Filters and Search */}
        <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-outline-variant/30 p-6 mb-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                🔍 Search Issues
              </label>
              <input
                type="text"
                placeholder="Search by title, description, or location..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Issue Type
              </label>
              <select
                value={filter.type}
                onChange={(e) => setFilter({ ...filter, type: e.target.value })}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="">All Types</option>
                <option value="pothole">🕳️ Pothole</option>
                <option value="streetlight">💡 Streetlight</option>
                <option value="water_leakage">💧 Water Leakage</option>
                <option value="garbage_overflow">🗑️ Garbage Overflow</option>
                <option value="public_property">🏛️ Public Property</option>
                <option value="other">⚠️ Other</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Status
              </label>
              <select
                value={filter.status}
                onChange={(e) => setFilter({ ...filter, status: e.target.value })}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="">All Status</option>
                <option value="pending">⏳ Pending</option>
                <option value="in_progress">🔧 In Progress</option>
                <option value="resolved">✅ Resolved</option>
              </select>
            </div>
          </div>
        </div>

        {/* Issues Grid */}
        {issues.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {issues.map((issue) => (
              <IssueCard
                key={issue._id}
                issue={issue}
                userRole={user?.role}
                onStatusUpdate={updateIssueStatus}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-12">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-12">
              <div className="text-6xl mb-4">🔍</div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">No issues found</h3>
              <p className="text-gray-600 mb-6">
                {searchTerm || filter.type || filter.status 
                  ? 'Try adjusting your filters or search terms.' 
                  : 'Be the first to report an infrastructure issue in your area!'}
              </p>
              {!searchTerm && !filter.type && !filter.status && (
                <button
                  onClick={() => window.location.href = '/report-issue'}
                  className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg font-medium transition-colors"
                >
                  📝 Report an Issue
                </button>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
